# =============================================================================
# kwin_lib/input_injection.py
# Generated by: Claude Sonnet 4.6
#
# Keyboard and mouse injection for phase 4 of kwin_restore.py.
#
# Mechanism
# ---------
# Uses the XDG RemoteDesktop portal (org.freedesktop.portal.RemoteDesktop)
# to inject keyboard and pointer events.  This is the correct Wayland path:
# KWin's private EIS interface (org.kde.KWin.EIS.RemoteDesktop) only grants
# POINTER_ABSOLUTE and TOUCH -- it deliberately withholds KEYBOARD.
#
# The portal requires a one-time user authorization dialog ("Allow wayland-desktop
# to control your keyboard and pointer?").  A restore token is saved to
# ~/.config/wayland-desktop/portal_session_token and reused on subsequent runs so
# the dialog never appears again.
#
# Portal methods used:
#   NotifyKeyboardKeycode(session, {}, keycode, state)   -- keyboard
#   NotifyPointerMotion(session, {}, dx, dy)             -- mouse move (relative)
#   NotifyPointerButton(session, {}, button, state)       -- mouse click
#   NotifyPointerAxisDiscrete(session, {}, axis, steps)   -- scroll
#
# NotifyPointerMotionAbsolute requires a PipeWire screen-capture stream node ID
# that is not available outside of a screen-capture session.  Instead, relative
# motion (NotifyPointerMotion) is used with a virtual cursor position seeded
# from KWin's reported cursor location at the start of each injection sequence.
#
# DSL reference: see docs/SNAPSHOT.md
