# ---- Portal constants -------------------------------------------------------

PORTAL_BUS  = "org.freedesktop.portal.Desktop"
PORTAL_PATH = "/org/freedesktop/portal/desktop"
PORTAL_RD   = "org.freedesktop.portal.RemoteDesktop"
PORTAL_REQ  = "org.freedesktop.portal.Request"
PORTAL_SESS = "org.freedesktop.portal.Session"

DEVICE_KEYBOARD = 1
DEVICE_POINTER  = 2

BTN_LEFT   = 0x110
BTN_RIGHT  = 0x111
BTN_MIDDLE = 0x112

AXIS_VERTICAL = 0
KEY_RELEASED  = 0
KEY_PRESSED   = 1
BTN_RELEASED  = 0
BTN_PRESSED   = 1

TOKEN_FILE = Path("~/.config/wayland-desktop/portal_session_token").expanduser()


