# ---- DSL actions ------------------------------------------------------------

@dataclass
class Action:
    kind:   str
    params: dict = field(default_factory=dict)


# ---- DSL scanner ------------------------------------------------------------

_TOKEN_RE = re.compile(r"\{([^}]*)\}")


def _parse_sleep(arg: str) -> int:
    arg = arg.strip()
    if arg.endswith("ms"):
        return int(float(arg[:-2]))
    if arg.endswith("s"):
        return int(float(arg[:-1]) * 1000)
    return int(arg)


def _parse_coords(arg: str) -> tuple[int, int]:
    parts = arg.split(",")
    if len(parts) != 2:
        raise ValueError(f"Expected 'x,y', got: {arg!r}")
    return int(parts[0].strip()), int(parts[1].strip())


def _parse_drag_coords(arg: str) -> tuple[tuple[int, int], tuple[int, int]]:
    """Parse 'x1, y1 to x2, y2' into two (x, y) tuples."""
    lo      = arg.lower()
    sep_idx = lo.find(" to ")
    if sep_idx == -1:
        raise ValueError(f"Expected 'x1,y1 to x2,y2', got: {arg!r}")
    start = _parse_coords(arg[:sep_idx])
    end   = _parse_coords(arg[sep_idx + 4:])
    return start, end


def parse_actions(dsl: str) -> list[Action]:
    actions: list[Action] = []
    text = dsl.replace("\r\n", "\n").replace("\r", "\n")
    pos = 0
    while pos < len(text):
        # Skip comment lines: a '#' at the start of a line (after optional
        # whitespace) causes the rest of that line to be ignored.
        # This allows pasting output from kwin_mouse-clicks.py directly
        # into input_actions without removing the comment lines first.
        if text[pos] == "#" or (
            text[pos] in (" ", "\t")
            and text[pos:].lstrip(" \t").startswith("#")
        ):
            end = text.find("\n", pos)
            pos = end + 1 if end != -1 else len(text)
            continue
        if text[pos:pos+2] == "{{":
            actions.append(Action("text", {"char": "{"}))
            pos += 2
            continue
        if text[pos] == "{":
            m = _TOKEN_RE.match(text, pos)
            if m:
                actions.extend(_parse_token(m.group(1).strip()))
                pos = m.end()
                continue
            actions.append(Action("text", {"char": "{"}))
            pos += 1
            continue
        if text[pos] == "\n":
            pos += 1
            continue
        actions.append(Action("text", {"char": text[pos]}))
        pos += 1
    return actions


def _parse_token(token: str) -> list[Action]:
    upper = token.upper()
    if upper.startswith("SLEEP ") or upper.startswith("WAIT "):
        return [Action("sleep", {"ms": _parse_sleep(token.split(None, 1)[1])})]
    if upper == "WAIT":
        return [Action("sleep", {"ms": 100})]
    if upper in ("FOCUS", "FOCUS-MAIN"):
        return [Action("focus", {})]
    if upper == "ACTIVE-WINDOW":
        return [Action("active_window", {})]
    if upper in ("TOOL", "FOCUS-TOOL"):
        return [Action("focus_tool", {})]
    if upper.startswith("PASS "):
        # {PASS key} — look up key in the Secret Service and type the result.
        key = token.split(None, 1)[1].strip()
        if not key:
            raise ValueError("PASS token requires a key argument: {PASS <key>}")
        return [Action("password", {"key": key})]
    if upper.startswith("MOVE "):
        x, y = _parse_coords(token.split(None, 1)[1])
        return [Action("move", {"x": x, "y": y})]
    if upper in ("SCROLLUP", "SCROLL_UP"):
        return [Action("scroll", {"direction": "up"})]
    if upper in ("SCROLLDOWN", "SCROLL_DOWN"):
        return [Action("scroll", {"direction": "down"})]
    for prefix, btn, win_rel in [
        ("WDRAG",  BTN_LEFT,   True),    # window-relative left drag
        ("WRDRAG", BTN_RIGHT,  True),    # window-relative right drag
        ("DRAG",   BTN_LEFT,   False),   # absolute left drag
    ]:
        if upper.startswith(prefix + " "):
            (x1, y1), (x2, y2) = _parse_drag_coords(token.split(None, 1)[1])
            return [Action("drag", {"x1": x1, "y1": y1, "x2": x2, "y2": y2,
                                    "button": btn, "window_relative": win_rel})]
    for prefix, btn, win_rel in [
        ("WCLICK",  BTN_LEFT,   True),
        ("WRCLICK", BTN_RIGHT,  True),   # window-relative right click
        ("CLICK",   BTN_LEFT,   False),
        ("RCLICK",  BTN_RIGHT,  False),
        ("MCLICK",  BTN_MIDDLE, False),
    ]:
        if upper == prefix:
            return [Action("click", {"x": None, "y": None,
                                     "button": btn, "window_relative": win_rel})]
        if upper.startswith(prefix + " "):
            x, y = _parse_coords(token.split(None, 1)[1])
            return [Action("click", {"x": x, "y": y,
                                     "button": btn, "window_relative": win_rel})]
    parts = [p.strip().upper() for p in upper.split("+")]
    modifiers: list[int] = []
    key_part: str = ""
    for p in parts:
        if p in _ALL_MODIFIERS:
            modifiers.append(_MODIFIER_CODES[p])
        elif p in _KEYCODES:
            key_part = p
        else:
            raise ValueError(
                f"Unknown key or modifier in token {{{token!r}}}: {p!r}\n"
                "See docs/SNAPSHOT.md for supported key names."
            )
    if not key_part:
        raise ValueError(f"No key found in token {{{token!r}}}: {parts}")
    return [Action("key", {"keycode": _KEYCODES[key_part], "modifiers": modifiers})]


# ---- Portal session helpers -------------------------------------------------

def _rand_token(n: int = 8) -> str:
    return "".join(random.choices(string.ascii_lowercase, k=n))


def _sender_component(conn: Gio.DBusConnection) -> str:
    return conn.get_unique_name().lstrip(":").replace(".", "_")


def _wait_for_response(
    conn:     Gio.DBusConnection,
    req_path: str,
    timeout:  int = 60,
) -> tuple[int, dict]:
    loop   = GLib.MainLoop()
    result = [None]

    def on_response(conn2, sender, obj_path, iface, signal, params, user_data):
        response, results = params
        result[0] = (int(response), dict(results))
        loop.quit()

    sub_id = conn.signal_subscribe(
        PORTAL_BUS, PORTAL_REQ, "Response",
        req_path, None,
        Gio.DBusSignalFlags.NONE,
        on_response, None,
    )
    GLib.timeout_add_seconds(timeout, loop.quit)
    loop.run()
    conn.signal_unsubscribe(sub_id)
    return result[0] or (1, {})


def _portal_call(
    conn:    Gio.DBusConnection,
    method:  str,
    args:    GLib.Variant,
    reply_t: str | None = None,
) -> GLib.Variant | None:
    return conn.call_sync(
        PORTAL_BUS, PORTAL_PATH, PORTAL_RD,
        method, args,
        GLib.VariantType(reply_t) if reply_t else None,
        Gio.DBusCallFlags.NONE, -1, None,
    )


# ---- InputInjector ----------------------------------------------------------

class InputInjector:
    """
    Context manager that opens an XDG RemoteDesktop portal session.

    On first use a KDE authorization dialog is shown; the user approves it
    once.  The restore_token is saved to
    ~/.config/wayland-desktop/portal_session_token and reused on subsequent runs
    so the dialog never appears again.

    All injection is via synchronous D-Bus calls to the portal -- no libei.
    """

    INTER_KEY_DELAY_MS = 30

    def __init__(self) -> None:
        self._conn:    Gio.DBusConnection | None = None
        self._session: str | None = None
        # Virtual cursor position for relative pointer motion.
        # Initialised from KWin's reported cursor location before phase 4 begins
        # so that the first relative move lands at the correct absolute position.
        self._cursor_x: float = 0.0
        self._cursor_y: float = 0.0

    def open(self) -> "InputInjector":
        """
        Open the XDG RemoteDesktop portal session.

        Separated from __enter__ so the portal can be opened early (before
        Phase 1) to ensure any stale-token KDE authorization dialog appears
        at startup rather than mid-restore during Phase 4.
        """
        self._conn    = Gio.bus_get_sync(Gio.BusType.SESSION, None)
        self._session = self._open_portal_session()
        return self

    def close(self) -> None:
        """Close the portal session and release all resources."""
        if self._conn and self._session:
            try:
                self._conn.call_sync(
                    PORTAL_BUS, self._session, PORTAL_SESS,
                    "Close", GLib.Variant("()", ()),
                    None, Gio.DBusCallFlags.NONE, -1, None,
                )
            except Exception:
                pass
        self._conn = self._session = None

    def __enter__(self) -> "InputInjector":
        return self.open()

    def __exit__(self, *_) -> None:
        self.close()

    def _open_portal_session(self, _retry: bool = False) -> str:
        conn   = self._conn
        sender = _sender_component(conn)

        restore_token = (
            TOKEN_FILE.read_text().strip() if TOKEN_FILE.exists() else None
        )

        # CreateSession
        rt0  = _rand_token()
        st0  = _rand_token()
        rp0  = f"/org/freedesktop/portal/desktop/request/{sender}/{rt0}"
        _portal_call(conn, "CreateSession", GLib.Variant("(a{sv})", ({
            "handle_token":         GLib.Variant("s", rt0),
            "session_handle_token": GLib.Variant("s", st0),
        },)), "(o)")
        resp, res = _wait_for_response(conn, rp0, timeout=10)
        if resp != 0:
            raise RuntimeError(f"Portal CreateSession failed (response={resp})")
        session_path = res.get("session_handle")
        if not session_path:
            raise RuntimeError(f"No session_handle in CreateSession response: {res}")

        # SelectDevices
        rt1  = _rand_token()
        rp1  = f"/org/freedesktop/portal/desktop/request/{sender}/{rt1}"
        opts: dict = {
            "handle_token": GLib.Variant("s", rt1),
            "types":        GLib.Variant("u", DEVICE_KEYBOARD | DEVICE_POINTER),
            "persist_mode": GLib.Variant("u", 2),
        }
        if restore_token:
            opts["restore_token"] = GLib.Variant("s", restore_token)
        _portal_call(conn, "SelectDevices",
                     GLib.Variant("(oa{sv})", (session_path, opts)), "(o)")
        resp2, _ = _wait_for_response(conn, rp1, timeout=10)
        if resp2 != 0:
            if restore_token and not _retry:
                # Stale restore token — delete it and try once more without it.
                # The second attempt will go through the full authorization flow
                # (KDE "Allow wayland-desktop to control input?" dialog).
                print(
                    "  [INJ ] Portal SelectDevices failed — restore token may be "
                    "stale. Deleting token and retrying (authorization dialog "
                    "will appear).",
                    file=sys.stderr,
                )
                try:
                    TOKEN_FILE.unlink()
                except Exception:
                    pass
                return self._open_portal_session(_retry=True)
            raise RuntimeError(f"Portal SelectDevices failed (response={resp2})")

        # Start (shows dialog on first use)
        rt2  = _rand_token()
        rp2  = f"/org/freedesktop/portal/desktop/request/{sender}/{rt2}"
        _portal_call(conn, "Start", GLib.Variant("(osa{sv})", (
            session_path, "",
            {"handle_token": GLib.Variant("s", rt2)},
        )), "(o)")
        resp3, res3 = _wait_for_response(conn, rp2, timeout=60)
        if resp3 != 0:
            raise RuntimeError(
                f"Portal Start failed or timed out (response={resp3}). "
                "If an authorization dialog appeared, please click Allow."
            )

        # Persist restore token
        new_token = res3.get("restore_token")
        if new_token:
            TOKEN_FILE.parent.mkdir(parents=True, exist_ok=True)
            TOKEN_FILE.write_text(str(new_token))

        return str(session_path)

    # ---- Low-level send helpers ---------------------------------------------

    def _notify(self, method: str, args: GLib.Variant) -> None:
        try:
            self._conn.call_sync(
                PORTAL_BUS, PORTAL_PATH, PORTAL_RD,
                method, args,
                None, Gio.DBusCallFlags.NONE, -1, None,
            )
        except Exception as exc:
            # Show domain/code/message for GLib.GError, full repr otherwise
            detail = getattr(exc, "message", None) or repr(exc)
            code   = getattr(exc, "code",    None)
            if code is not None:
                detail = f"{detail} (code={code})"
            raise RuntimeError(f"{method} failed: {detail}") from exc

    def send_key(self, keycode: int, modifiers: list[int]) -> None:
        """Press modifiers, press/release key, release modifiers."""
        sess = self._session
        # Pass {} directly — PyGObject converts it to a{sv}.
        # Do NOT pre-create GLib.Variant("a{sv}", {}) — passing a Variant
        # inside another Variant constructor wraps it as 'v', not 'a{sv}'.
        for mod in modifiers:
            self._notify("NotifyKeyboardKeycode",
                         GLib.Variant("(oa{sv}iu)", (sess, {}, mod, KEY_PRESSED)))
        self._notify("NotifyKeyboardKeycode",
                     GLib.Variant("(oa{sv}iu)", (sess, {}, keycode, KEY_PRESSED)))
        self._notify("NotifyKeyboardKeycode",
                     GLib.Variant("(oa{sv}iu)", (sess, {}, keycode, KEY_RELEASED)))
        for mod in reversed(modifiers):
            self._notify("NotifyKeyboardKeycode",
                         GLib.Variant("(oa{sv}iu)", (sess, {}, mod, KEY_RELEASED)))

    def send_char(self, char: str) -> None:
        entry = _CHAR_MAP.get(char)
        if entry is None:
            print(f"  [INJ ] Skipping unmapped character: {char!r}", file=sys.stderr)
            return
        keycode, needs_shift = entry
        self.send_key(keycode, [_MODIFIER_CODES["SHIFT"]] if needs_shift else [])

    def init_cursor(self, kwin: Any) -> None:
        """
        Seed the virtual cursor position from KWin's current cursor location.
        Call this once before the first pointer move so that the first relative
        delta lands at the correct absolute target position.
        """
        try:
            info = kwin.desktops.active_window_and_cursor()
            self._cursor_x = float(info.get("cursor_x", 0))
            self._cursor_y = float(info.get("cursor_y", 0))
        except Exception:
            self._cursor_x = self._cursor_y = 0.0

    def send_pointer_abs(self, x: float, y: float) -> None:
        """
        Move the pointer to absolute compositor position (x, y).

        The XDG RemoteDesktop portal's NotifyPointerMotionAbsolute requires a
        PipeWire screen-capture stream node ID that we do not have.  Instead
        we use NotifyPointerMotion (relative) and compute the delta from a
        tracked virtual cursor position that is seeded from KWin's reported
        cursor location before phase 4 begins.
        """
        dx = x - self._cursor_x
        dy = y - self._cursor_y
        self._cursor_x = x
        self._cursor_y = y
        self._notify("NotifyPointerMotion",
                     GLib.Variant("(oa{sv}dd)", (self._session, {}, dx, dy)))

    def send_button(self, button: int, pressed: bool) -> None:
        self._notify("NotifyPointerButton",
                     GLib.Variant("(oa{sv}iu)", (
                         self._session, {},
                         button, BTN_PRESSED if pressed else BTN_RELEASED,
                     )))

    def send_scroll(self, direction: str) -> None:
        steps = -1 if direction == "up" else 1
        self._notify("NotifyPointerAxisDiscrete",
                     GLib.Variant("(oa{sv}ui)", (
                         self._session, {}, AXIS_VERTICAL, steps,
                     )))

    # ---- High-level action execution ----------------------------------------

    def focus_window(self, uuid: str, kwin: Any) -> None:
        kwin.windows.raise_window(uuid)
        time.sleep(0.3)

    def inject_actions(
        self,
        actions:         list[Action],
        uuid:            str,
        kwin:            Any,
        logger:          Any,
        window_x:        int = 0,
        window_y:        int = 0,
        secret_service:  Any = None,   # SecretService instance or None
        click_indicator: Any = None,   # ClickIndicator instance or None
        tool_uuid:       list = None,  # one-element list holding current tool UUID
    ) -> None:
        # tool_uuid is a one-element list so it can be mutated by reference
        # across calls from the run_input_actions loop.  None means no tool
        # window has been captured yet.
        if tool_uuid is None:
            tool_uuid = [None]
        for action in actions:
            if action.kind == "key":
                self.send_key(action.params["keycode"], action.params["modifiers"])
                time.sleep(self.INTER_KEY_DELAY_MS / 1000)
            elif action.kind == "text":
                self.send_char(action.params["char"])
                time.sleep(self.INTER_KEY_DELAY_MS / 1000)
            elif action.kind == "sleep":
                time.sleep(action.params["ms"] / 1000)
            elif action.kind == "focus":
                # {FOCUS} / {FOCUS-MAIN} — raise the main target window
                self.focus_window(uuid, kwin)
                self.init_cursor(kwin)
            elif action.kind == "active_window":
                # {ACTIVE-WINDOW} — capture the currently active window as the
                # tool window.  Typically placed after a {SLEEP} that gives a
                # just-opened dialog time to appear and steal focus.
                try:
                    info = kwin.desktops.active_window_and_cursor()
                    active_id = info.get("active_id", "").strip("{}")
                    if active_id and active_id != uuid.strip("{}"):
                        tool_uuid[0] = info.get("active_id", "")
                        caption = info.get("caption", "")
                        logger.info(
                            f"    Tool window captured: {active_id[:20]}"
                            + (f" ({caption!r})" if caption else "")
                        )
                    else:
                        logger.warn(
                            "    {ACTIVE-WINDOW}: active window is the main "
                            "window — no tool window captured"
                        )
                        tool_uuid[0] = None
                except Exception as exc:
                    logger.warn(f"    {{ACTIVE-WINDOW}} failed: {exc}")
            elif action.kind == "focus_tool":
                # {FOCUS-TOOL} / {TOOL} — raise the captured tool window, or
                # fall back to the main window if none has been captured.
                if tool_uuid[0]:
                    try:
                        self.focus_window(tool_uuid[0], kwin)
                        self.init_cursor(kwin)
                    except Exception as exc:
                        logger.warn(
                            f"    {{FOCUS-TOOL}}: could not raise tool window "
                            f"({exc}) — falling back to main window"
                        )
                        self.focus_window(uuid, kwin)
                        self.init_cursor(kwin)
                else:
                    logger.warn(
                        "    {FOCUS-TOOL}: no tool window has been captured "
                        "— raising main window instead"
                    )
                    self.focus_window(uuid, kwin)
                    self.init_cursor(kwin)
            elif action.kind == "move":
                ax, ay = float(action.params["x"]), float(action.params["y"])
                if click_indicator:
                    click_indicator.show_click(ax, ay)
                self.send_pointer_abs(ax, ay)
            elif action.kind == "password":
                # Resolve key via Secret Service, then type each character.
                # Both the overlay and the progress window are hidden first so
                # they cannot block the KeePassXC authorization dialog, then
                # shown again after typing completes.
                key = action.params["key"]
                if secret_service is None:
                    raise RuntimeError(
                        f"{{PASS {key}}} token found but use_secret_service is "
                        "not enabled in config.yaml — set use_secret_service: true"
                    )
                if click_indicator:
                    click_indicator.hide()
                logger.hide_window()
                try:
                    password = secret_service.get_password(key)
                finally:
                    logger.show_window()
                    if click_indicator:
                        click_indicator.show()
                for ch in password:
                    self.send_char(ch)
                    time.sleep(self.INTER_KEY_DELAY_MS / 1000)
            elif action.kind == "click":
                p = action.params
                if p["x"] is not None:
                    ax = (window_x + p["x"]) if p.get("window_relative") else p["x"]
                    ay = (window_y + p["y"]) if p.get("window_relative") else p["y"]
                    if click_indicator:
                        click_indicator.show_click(float(ax), float(ay))
                    self.send_pointer_abs(float(ax), float(ay))
                self.send_button(p["button"], True)
                time.sleep(0.05)
                self.send_button(p["button"], False)
            elif action.kind == "drag":
                # Move to start, press, move to end, release.
                # The 50 ms pauses give the application time to register each
                # phase of the drag before the next portal event arrives.
                p   = action.params
                ax1 = (window_x + p["x1"]) if p.get("window_relative") else p["x1"]
                ay1 = (window_y + p["y1"]) if p.get("window_relative") else p["y1"]
                ax2 = (window_x + p["x2"]) if p.get("window_relative") else p["x2"]
                ay2 = (window_y + p["y2"]) if p.get("window_relative") else p["y2"]
                if click_indicator:
                    click_indicator.show_click(float(ax1), float(ay1))
                self.send_pointer_abs(float(ax1), float(ay1))
                time.sleep(0.05)
                self.send_button(p["button"], True)
                time.sleep(0.05)
                if click_indicator:
                    click_indicator.show_click(float(ax2), float(ay2))
                self.send_pointer_abs(float(ax2), float(ay2))
                time.sleep(0.05)
                self.send_button(p["button"], False)
            elif action.kind == "scroll":
                self.send_scroll(action.params["direction"])


# ---- Phase 4 driver ---------------------------------------------------------

def run_input_actions(
    result,
    injector:        InputInjector,
    kwin:            Any,
    logger:          Any,
    dry_run:         bool = False,
    secret_service:  Any  = None,   # SecretService instance or None
    click_indicator: Any  = None,   # ClickIndicator instance or None
) -> None:
    """Phase 4: execute input_actions DSL for one restore result."""
    entry = result.entry
    dsl   = (entry.input_actions or "").strip()
    if not dsl:
        return

    logger.info(f"  Input actions: {entry.app_alias!r}")

    if dry_run:
        preview = dsl.replace("\n", " ")
        if len(preview) > 60:
            preview = preview[:57] + "..."
        logger.info(f"    [dry-run] Would inject: {preview!r}")
        return

    try:
        actions = parse_actions(dsl)
    except ValueError as exc:
        logger.warn(f"    DSL parse error -- skipping: {exc}")
        return

    window_x = window_y = 0
    try:
        geom = kwin.windows.get_screen_geometry(result.uuid)
        window_x = geom.get("win_x", 0)
        window_y = geom.get("win_y", 0)
    except Exception:
        pass

    try:
        injector.focus_window(result.uuid, kwin)
    except Exception as exc:
        logger.warn(f"    Could not focus window before injection: {exc}")

    # Verify that the target window is actually the active (focused) window
    # before starting injection.  raise_window() is asynchronous — KWin
    # may still be processing the focus change when the first portal event
    # fires.  Retry up to 3 times with 300ms pauses.
    _MAX_FOCUS_RETRIES = 3
    _FOCUS_RETRY_DELAY = 0.3
    for attempt in range(_MAX_FOCUS_RETRIES):
        try:
            info       = kwin.desktops.active_window_and_cursor()
            active_id  = info.get("active_id", "").strip("{}")
            target_id  = result.uuid.strip("{}")
            if active_id == target_id:
                break
            # Not focused yet — raise again and wait
            if attempt < _MAX_FOCUS_RETRIES - 1:
                logger.info(
                    f"    Focus not confirmed (attempt {attempt + 1}/"
                    f"{_MAX_FOCUS_RETRIES}) — retrying raise_window"
                )
                injector.focus_window(result.uuid, kwin)
            else:
                caption = info.get("caption", "")
                logger.warn(
                    f"    Target window not active after "
                    f"{_MAX_FOCUS_RETRIES} attempts — "
                    f"active window is {active_id[:20]!r}"
                    + (f" ({caption!r})" if caption else "")
                    + " — proceeding anyway"
                )
        except Exception:
            break   # KWin query failed; proceed without verification

    n_ok = n_skip = 0
    # One-element list so inject_actions can mutate tool_uuid[0] across calls
    tool_uuid: list = [None]
    # Seed the virtual cursor position so relative moves land correctly
    injector.init_cursor(kwin)
    for action in actions:
        try:
            injector.inject_actions(
                [action], result.uuid, kwin, logger,
                window_x=window_x, window_y=window_y,
                secret_service=secret_service,
                click_indicator=click_indicator,
                tool_uuid=tool_uuid,
            )
            n_ok += 1
        except Exception as exc:
            logger.warn(f"    Action {action.kind!r} failed (non-fatal): {exc}")
            n_skip += 1

    summary = f"    Done: {n_ok} action(s)"
    if n_skip:
        summary += f", {n_skip} skipped"
    logger.ok(summary)
